            }
        }
        catch (Exception ex)
        {
            Console.WriteLine("Error loading session: " + ex.Message);
            return null;
        }
    }

    private string GetSessionFilePath(int userId)
    {
        return Path.Combine(_sessionPath, $"{userId}.bin");
    }
}

